            CssRule::CounterStyle(r) => CssRuleRef::CounterStyle(r.as_ref()),
            CssRule::Keyframes(r) => CssRuleRef::Keyframes(r.as_ref()),
            CssRule::Margin(r) => CssRuleRef::Margin(r.as_ref()),
